/* ── ADD / DELETE / SS ── */
function addEj(dia, sid) {
  var a = gA(S.cid); if (!a) return;
  var ses = getSes(S.cw, dia);
  if (!ses) {
    dbPost('sesiones', {bloque_id:S.bloque.id, semana:S.cw, dia:dia, nombre_dia:DT[dia-1]||'Entrenamiento'})
      .then(function(d) {
        var ns = Array.isArray(d) ? d[0] : d;
        S.sesiones.push(ns); S.ejercicios[ns.id] = [];
        addEjSes(ns.id);
      });
  } else {
    addEjSes(ses.id);
  }
}
function addEjSes(sid) {
  var ord = (S.ejercicios[sid] || []).length;
  dbPost('ejercicios', {sesion_id:sid, nombre:'', grupo:'Pecho', series:3, reps:'10-12', peso:0, rpe:7, obs:'', orden:ord, ss_grupo:null})
    .then(function(d) {
      var ej = Array.isArray(d) ? d[0] : d;
      if (!S.ejercicios[sid]) S.ejercicios[sid] = [];
      S.ejercicios[sid].push(ej);
      rSess();
      setTimeout(function() {
        var rows = document.querySelectorAll('#reg-left .xt tbody tr');
        if (rows.length) { var inp = rows[rows.length-1].querySelector('.xn'); if (inp) inp.focus(); }
      }, 60);
    }).catch(function() { toast('Error al agregar'); });
}

function delEj(id) {
  dbDel('ejercicios', 'id=eq.' + id).then(function() {
    for (var i = 0; i < S.sesiones.length; i++) {
      var ejs = S.ejercicios[S.sesiones[i].id] || [];
      for (var j = 0; j < ejs.length; j++) { if (ejs[j].id === id) { ejs.splice(j,1); break; } }
    }
    rSess();
  }).catch(function() { toast('Error al eliminar'); });
}

function togSS(id, dia) {
  for (var i = 0; i < S.sesiones.length; i++) {
    var ejs = S.ejercicios[S.sesiones[i].id] || [];
    for (var j = 0; j < ejs.length; j++) {
      if (ejs[j].id !== id) continue;
      var e = ejs[j], nss = null;
      if (e.ss_grupo) {
        nss = null;
      } else {
        var p = j>0 ? ejs[j-1].ss_grupo : null, n = j<ejs.length-1 ? ejs[j+1].ss_grupo : null;
        if (p) nss = p;
        else if (n) nss = n;
        else {
          nss = 'ss' + Date.now();
          if (j < ejs.length-1 && !ejs[j+1].ss_grupo) {
            ejs[j+1].ss_grupo = nss;
            dbPatch('ejercicios', 'id=eq.' + ejs[j+1].id, {ss_grupo:nss});
          }
        }
      }
      e.ss_grupo = nss;
      dbPatch('ejercicios', 'id=eq.' + id, {ss_grupo:nss}).then(function() { rSess(); });
      return;
    }
  }
}

