    mRows += '<div style="position:absolute;top:0;left:0;height:100%;width:'+bp+'%;background:'+z.col+';opacity:.88;border-radius:6px;display:flex;align-items:center;padding-left:7px"><span class="mbar-val">'+s+'</span></div>';
